238	function matchMatrixAcpConversation(params: {
239	  bindingConversationId: string;
240	  conversationId: string;
241	  parentConversationId?: string;
242	}) {
243	  const binding = normalizeMatrixAcpConversationId(params.bindingConversationId);
244	  if (!binding) {
245	    return null;
246	  }
247	  if (binding.conversationId === params.conversationId) {
248	    return { conversationId: params.conversationId, matchPriority: 2 };
249	  }
250	  if (
251	    params.parentConversationId &&
252	    params.parentConversationId !== params.conversationId &&
253	    binding.conversationId === params.parentConversationId
254	  ) {
255	    return {
256	      conversationId: params.parentConversationId,
257	      matchPriority: 1,
258	    };
259	  }
260	  return null;
261	}
