263	function resolveMatrixCommandConversation(params: {
264	  threadId?: string;
265	  originatingTo?: string;
266	  commandTo?: string;
267	  fallbackTo?: string;
268	}) {
269	  const parentConversationId = [params.originatingTo, params.commandTo, params.fallbackTo]
270	    .map((candidate) => {
271	      const trimmed = candidate?.trim();
272	      if (!trimmed) {
273	        return undefined;
274	      }
275	      const target = resolveMatrixTargetIdentity(trimmed);
276	      return target?.kind === "room" ? target.id : undefined;
277	    })
278	    .find((candidate): candidate is string => Boolean(candidate));
279	  if (params.threadId) {
280	    return {
281	      conversationId: params.threadId,
282	      ...(parentConversationId ? { parentConversationId } : {}),
283	    };
284	  }
285	  return parentConversationId ? { conversationId: parentConversationId } : null;
286	}
