import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import type { OpenClawConfig } from "openclaw/plugin-sdk/core";
import type { PulseBoardConfig } from "./types.js";

const DEFAULT_ACCOUNT_ID = "default";

/** Augmented config type for accessing pulseboard-specific channel config. */
type PulseBoardCoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/** Resolved account shape used across config, gateway, and outbound adapters. */
type ResolvedPulseBoardAccount = {
  accountId: string;
  configured: boolean;
  boardUrl: string | undefined;
  apiToken: string | undefined;
  username: string | undefined;
};

function resolvePulseBoardAccount(
  cfg: PulseBoardCoreConfig,
  accountId: string,
): ResolvedPulseBoardAccount {
  const accounts = cfg.channels?.pulseboard?.accounts;
  const accountCfg = accounts?.[accountId];
  return {
    accountId,
    configured: !!(accountCfg?.boardUrl && accountCfg?.apiToken),
    boardUrl: accountCfg?.boardUrl,
    apiToken: accountCfg?.apiToken,
    username: accountCfg?.username,
  };
}

export const pulseBoardPlugin = createChatChannelPlugin<ResolvedPulseBoardAccount>({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Connect to PulseBoard bulletin messaging.",
      order: 110,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (cfg) => {
        const accounts = (cfg as PulseBoardCoreConfig).channels?.pulseboard?.accounts;
        return accounts ? Object.keys(accounts) : [];
      },
      resolveAccount: (cfg, accountId) =>
        resolvePulseBoardAccount(cfg as PulseBoardCoreConfig, accountId ?? DEFAULT_ACCOUNT_ID),
    },
    setup: {
      // Stub: return config unchanged; real implementation would apply board URL and token.
      applyAccountConfig: ({ cfg }) => cfg,
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.accountId}] PulseBoard: connecting to ${ctx.account.boardUrl ?? "(unconfigured)"}`,
        );
      },
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, accountId }) => {
      // Stub: real implementation would POST to the PulseBoard API.
      const messageId = `pb-${Date.now()}`;
      return attachChannelToResult("pulseboard", { to, messageId });
    },
  },
});

